  ('judicial-f0899a01-moex-00462', 'judicial-f0899a01', 'judicial-f0899a01-moex-111-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '甲報考軍校錄取後與該校簽訂行政契約，約定學生遭開除學籍時，應賠償軍校所給付予學生之一切費用。 嗣甲遭開除學籍，軍校擬對甲請求賠償，下列敘述何者正確？', '["若軍校以書面限期命甲賠償，該書面非行政處分", "若該行政契約有甲自願接受執行之約定，軍校得作成行政處分，限期命甲賠償；甲逾期仍不履行，得依 行政執行法移送強制執行", "若該行政契約未約定甲自願接受執行，軍校仍得作成行政處分，限期命甲賠償", "該行政契約屬於行政上之和解契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:47+00:00", "source_pdf_sha1": "5ef74afcdd2c", "answer_pdf_sha1": "e5ded5215165", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "202", "s": "0307", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
